mapper.select:
SELECT ai.*, ac.category_name as categoryName, CASE ai.status WHEN 1 THEN '正常' WHEN 2 THEN '维修中' WHEN 3 THEN '闲置' WHEN 4 THEN '已报废' ELSE '未知' END as statusText FROM asset_info ai LEFT JOIN asset_category ac ON ai.category_id = ac.id
AND (ai.asset_name LIKE CONCAT('%', #{keyword}, '%') OR ai.asset_code LIKE CONCAT('%', #{keyword}, '%') OR ai.serial_number LIKE CONCAT('%', #{keyword}, '%') OR ai.responsible_person LIKE CONCAT('%', #{keyword}, '%'))
AND ai.category_id = #{categoryId}
AND ai.status = #{status}
AND ai.building = #{building}
AND ai.floor = #{floor}
AND ai.room_number = #{roomNumber}
ORDER BY ai.create_time DESC
